class TiledGEMM:
    """Naive vs tiled matrix multiply with transaction counting."""

    def __init__(self):
        pass

    def naive_matmul(self, A, B):
        """Naive matmul counting global memory reads."""
        M = len(A)
        K = len(A[0])
        N = len(B[0])
        C = [[0.0] * N for _ in range(M)]
        global_reads = 0

        for i in range(M):
            for j in range(N):
                total = 0.0
                for k in range(K):
                    total += A[i][k] * B[k][j]
                    global_reads += 2  # One A read, one B read
                C[i][j] = total

        return C, global_reads

    def tiled_matmul(self, A, B, tile_size):
        """Tiled matmul with shared memory simulation."""
        M = len(A)
        K = len(A[0])
        N = len(B[0])
        C = [[0.0] * N for _ in range(M)]
        global_reads = 0
        shared_reads = 0

        num_tiles_k = (K + tile_size - 1) // tile_size

        for bi in range(0, M, tile_size):
            for bj in range(0, N, tile_size):
                for t in range(num_tiles_k):
                    # Load tile_A from global memory
                    tile_A = [[0.0] * tile_size for _ in range(tile_size)]
                    for ti in range(tile_size):
                        for tk in range(tile_size):
                            r = bi + ti
                            c = t * tile_size + tk
                            if r < M and c < K:
                                tile_A[ti][tk] = A[r][c]
                                global_reads += 1

                    # Load tile_B from global memory
                    tile_B = [[0.0] * tile_size for _ in range(tile_size)]
                    for tk in range(tile_size):
                        for tj in range(tile_size):
                            r = t * tile_size + tk
                            c = bj + tj
                            if r < K and c < N:
                                tile_B[tk][tj] = B[r][c]
                                global_reads += 1

                    # Compute from shared memory
                    for ti in range(tile_size):
                        for tj in range(tile_size):
                            row = bi + ti
                            col = bj + tj
                            if row < M and col < N:
                                for tk in range(tile_size):
                                    C[row][col] += tile_A[ti][tk] * tile_B[tk][tj]
                                    shared_reads += 2

        return C, global_reads, shared_reads

    def analyze(self, M, K, N, tile_size):
        """Compare naive vs tiled and return analysis."""
        import random
        random.seed(42)

        A = [[random.random() for _ in range(K)] for _ in range(M)]
        B = [[random.random() for _ in range(N)] for _ in range(K)]

        C_naive, naive_reads = self.naive_matmul(A, B)
        C_tiled, tiled_global, tiled_shared = self.tiled_matmul(A, B, tile_size)

        max_diff = 0.0
        for i in range(M):
            for j in range(N):
                diff = abs(C_naive[i][j] - C_tiled[i][j])
                max_diff = max(max_diff, diff)

        ratio = naive_reads / tiled_global if tiled_global > 0 else float('inf')

        return {
            'naive_reads': naive_reads,
            'tiled_global_reads': tiled_global,
            'tiled_shared_reads': tiled_shared,
            'reduction_ratio': ratio,
            'correct': max_diff < 1e-4,
        }
